import { getRequestHeaders, type H3Event } from 'h3'
import { checksums } from '#content/manifest'

async function fetchContent<T>(
  event: H3Event | undefined,
  collection: string,
  path: string,
  options: NonNullable<Parameters<typeof $fetch>[1]>,
): Promise<T> {
  const headers = event ? getRequestHeaders(event) : {}
  headers['accept-encoding'] = undefined // prevent unsupported enconding issue (https://github.com/nuxt/content/pull/3701)

  const url = `/__nuxt_content/${collection}/${path}`
  const fetchOptions = {
    ...options,
    headers: {
      ...headers,
      ...options.headers,
    },
    query: { v: checksums[String(collection)], t: import.meta.dev ? Date.now() : undefined },
  }
  return event ? await event.$fetch(url, fetchOptions) : await $fetch(url, fetchOptions)
}

export async function fetchDatabase(event: H3Event | undefined, collection: string): Promise<string> {
  return fetchContent(event, collection, 'sql_dump.txt', {
    responseType: 'text',
    headers: {
      'content-type': 'text/plain',
    },
  })
}

export async function fetchQuery<Item>(event: H3Event | undefined, collection: string, sql: string): Promise<Item[]> {
  return fetchContent(event, collection, 'query', {
    headers: {
      'content-type': 'application/json',
    },
    method: 'POST',
    body: {
      sql,
    },
  })
}

import type { NuxtDevtoolsHostClient } from '@nuxt/devtools-kit/types'
import type { Ref } from 'vue'
import { shallowRef } from 'vue'

let clientRef: Ref<NuxtDevtoolsHostClient | undefined> | undefined
const fns = [] as ((client: NuxtDevtoolsHostClient) => void)[]

export function onDevtoolsHostClientConnected(fn: (client: NuxtDevtoolsHostClient) => void) {
  fns.push(fn)

  if (typeof window === 'undefined')
    return

  // eslint-disable-next-line ts/ban-ts-comment
  // @ts-ignore injection
  if (window.__NUXT_DEVTOOLS_HOST__) {
    // eslint-disable-next-line ts/ban-ts-comment
    // @ts-ignore injection
    fns.forEach(fn => fn(window.__NUXT_DEVTOOLS_HOST__))
  }

  Object.defineProperty(window, '__NUXT_DEVTOOLS_HOST__', {
    set(value) {
      if (value)
        fns.forEach(fn => fn(value))
    },
    get() {
      return clientRef!.value
    },
    configurable: true,
  })

  return () => {
    fns.splice(fns.indexOf(fn), 1)
  }
}

export function useDevtoolsHostClient(): Ref<NuxtDevtoolsHostClient | undefined> {
  if (!clientRef) {
    clientRef = shallowRef<NuxtDevtoolsHostClient | undefined>()

    onDevtoolsHostClientConnected(setup)
  }

  function setup(client: NuxtDevtoolsHostClient) {
    clientRef!.value = client
  }

  return clientRef
}

import type { Nitro } from 'nitropack'
import type { NuxtDevtoolsServerContext, ScannedNitroTasks, ServerFunctions } from '../types'
import { debounce } from 'perfect-debounce'
import { watchStorageMount } from './storage-watch'

export function setupServerTasksRPC({ nuxt, refresh }: NuxtDevtoolsServerContext) {
  let nitro: Nitro
  let unwatchStorage: (() => Promise<void> | void) | undefined

  let cache: ScannedNitroTasks | null = null

  const refreshDebounced = debounce(() => {
    cache = null
    refresh('getServerTasks')
  }, 500)

  nuxt.hook('nitro:init', (_) => {
    nitro = _
    cache = null
    refresh('getServerTasks')
  })

  nuxt.hook('ready', async () => {
    if (!nitro)
      return

    await unwatchStorage?.()
    unwatchStorage = await watchStorageMount(nitro.storage, 'src', (_event, key) => {
      if (key.startsWith('src:tasks:'))
        refreshDebounced()
    })
  })

  nuxt.hook('close', async () => {
    await unwatchStorage?.()
    unwatchStorage = undefined
  })

  function scan() {
    if (cache)
      return cache

    cache = (() => {
      if (!nitro) {
        return {
          tasks: {},
          scheduledTasks: {},
        }
      }
      return {
        tasks: nitro.options.tasks,
        scheduledTasks: Object.entries(nitro.options.scheduledTasks ?? {})
          .reduce<Record<string, string[]>>((acc, [cron, tasks]) => {
            acc[cron] = Array.isArray(tasks) ? tasks : [tasks]
            return acc
          }, {}),
      }
    })()

    return cache
  }

  return {
    getServerTasks() {
      return scan()
    },
  } satisfies Partial<ServerFunctions>
}

import { dirname, join } from 'node:path'
import fs from 'node:fs/promises'
import type { Nuxt } from '@nuxt/schema'
import type { ESLintConfigGenAddon } from '../../types'
import type { ModuleOptions } from '../../module'
import { createAddonGlobals } from './addons/globals'
import { setupDevToolsIntegration } from './devtools'
import { initRootESLintConfig } from './init'
import { generateESLintConfig } from './generate'

export async function setupConfigGen(options: ModuleOptions, nuxt: Nuxt) {
  const {
    autoInit = true,
  } = typeof options.config !== 'boolean' ? options.config || {} : {}

  const defaultAddons = [
    createAddonGlobals(nuxt),
  ]

  nuxt.hook('prepare:types', ({ declarations, nodeReferences }) => {
    declarations.push('/// <reference path="./eslint-typegen.d.ts" />')
    if (nodeReferences)
      nodeReferences.push({ path: join(nuxt.options.buildDir, 'eslint-typegen.d.ts') })
  })

  let _configFile: string = undefined!

  async function writeConfigFile() {
    const addons: ESLintConfigGenAddon[] = [
      ...defaultAddons,
    ]
    await nuxt.callHook('eslint:config:addons', addons)
    const { code, codeDts, configFile } = await generateESLintConfig(options, nuxt, addons)
    await fs.mkdir(dirname(configFile), { recursive: true })
    await fs.writeFile(configFile, code, 'utf-8')
    await fs.writeFile(configFile.replace(/\.mjs$/, '.d.mts'), codeDts, 'utf-8')
    _configFile = configFile
  }

  setupDevToolsIntegration(options, nuxt)

  await writeConfigFile()
  nuxt.hook('builder:generateApp', async () => {
    await writeConfigFile()
  })

  if (autoInit) {
    await initRootESLintConfig(nuxt, _configFile)
  }
}

import { $fetch } from 'ofetch'
import type { feedsInfo } from '~~/utils/api'
